Hamming code is an error-correcting code that can detect and correct single-bit errors. It adds parity bits to the data bits to detect and correct errors.

Here is a Python code that implements Hamming code:

```python
def encode(data):
    # Calculate number of parity bits needed
    m = len(data)
    p = 0
    while 2**p < m + p + 1:
        p += 1

    # Add parity bits
    codeword = [0] * (m + p)
    for i in range(m):
        codeword[i] = data[i]

    # Calculate parity bits
    for i in range(p):
        parity_bit = 0
        for j in range(m):
            if (j + 1) & (2**i) != 0:
                parity_bit ^= codeword[j]
        codeword[m + i] = parity_bit

    return codeword

def decode(codeword):
    # Check if single-bit error
    error = 0
    for i in range(len(codeword) - 1):
        parity_bit = 0
        for j in range(len(codeword)):
            if (j + 1) & (2**i) != 0:
                parity_bit ^= codeword[j]
        if parity_bit == 1:
            error += 1

    # If single-bit error, correct it
    if error == 1: 
        for i in range(len(codeword) - 1):
            parity_bit = 0
            for j in range(len(codeword)):
                if (j + 1) & (2**i) != 0:
                    parity_bit ^= codeword[j]
            if parity_bit == 1:
                codeword[i] = codeword[i] ^ 1 

    # Remove parity bits        
    data = []
    for i in range(1, len(codeword)):
        if 2**i > len(codeword):
            break
        data.append(codeword[i-1])

    return data 
```

Example usage:
```python
data = [1, 0, 1, 0, 1, 0, 1] 
codeword = encode(data)  # [1, 0, 1, 0, 1, 1, 0, 1]
decoded = decode(codeword) # [1, 0, 1, 0, 1

Hamming code can be used to encode and decode integer data as well. Here is how it can be implemented for 32-bit integers:

```python
def encode(data):
    # Calculate number of parity bits needed
    m = 32  # 32 data bits
    p = 0
    while 2**p < m + p + 1:
        p += 1  # 7 parity bits needed

    # Add parity bits
    codeword = 0
    for i in range(m):
        codeword |= (data & 1) << i
        data >>= 1

    # Calculate parity bits
    for i in range(p):
        parity_bit = 0
        for j in range(m):
            if (j + 1) & (2**i) != 0:
                parity_bit ^= (codeword >> j) & 1
        codeword |= (parity_bit << (m + i))

    return codeword

def decode(codeword):
    # Check if single-bit error
    error = 0
    for i in range(p):
        parity_bit = 0
        for j in range(m + p):
            if (j + 1) & (2**i) != 0:
                parity_bit ^= (codeword >> j) & 1
        if parity_bit == 1:
            error += 1

    # If single-bit error, correct it
    if error == 1: 
        for i in range(p):
            parity_bit = 0
            for j in range(m + p):
                if (j + 1) & (2**i) != 0:
                    parity_bit ^= (codeword >> j) & 1
            if parity_bit == 1:
                codeword ^= (1 << i)

    # Remove parity bits        
    data = 0
    for i in range(m):
        data |= (codeword & 1) << i
        codeword >>= 1

    return data
```

Example usage:
```python
data = 0b11010101  # 338
codeword = encode(data)  # 0b110101011010110 
decoded = decode(codeword) # 0b11010101
```
